text:
{
  "formal_minutes": {
    "decisions": [
      "공개 릴리스 목표는 스모크 테스트 통과를 조건으로 금요일 15:00 KST로 정했다.",
      "packageName mismatch가 발생하면 먼저 패키지 설정을 확인한다.",
      "계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토한다."
    ],
    "non_decisions": {
      "rejected_proposals": [
        "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경하는 제안은 거절되었다."
      ],
      "internal_stretch_goals": [
        "수요일 릴리스는 확정 일정이 아니라 내부 stretch goal로만 남았다."
      ],
      "unassigned_items": [
        "README 설치 단계는 목요일까지 가능하면 검토해야 한다는 의견이 있었지만, 담당자는 지정되지 않았다."
      ]
    },
    "risks": [
      "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다.",
      "README 설치 단계가 오래된 경우 릴리스 노트가 사용자를 오도할 수 있다."
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "원문 명시"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "원문 명시"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "확정, 정확한 마감 없음",
      "source_certainty": "원문 명시"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 검토한다.",
      "due": "목요일까지 가능하면",
      "status": "제안됨, 담당자 미지정",
      "source_certainty": "원문 명시"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 스모크 테스트 결과가 금요일 10:00 KST까지 공유되었는지 확인한다.",
      "Doyun의 failure triage note가 action_items.md에 금요일 12:00 KST까지 작성되었는지 확인한다.",
      "스모크 결과 공유 후 Hara가 tarball 경로를 확인했는지 확인한다.",
      "README 설치 단계 검토의 담당자와 확정 마감 여부를 정한다.",
      "최종 릴리스 승인 권한자를 확인한다.",
      "릴리스 노트에 내부 수요일 stretch goal을 언급할지 결정한다."
    ],
    "do_not_invent": [
      "고객명",
      "외부 파트너",
      "예산",
      "보안 사고",
      "운영 장애",
      "법무 승인 요구사항",
      "지정되지 않은 담당자",
      "명시되지 않은 마감"
    ]
  },
  "non_invention_rules": [
    "고객 또는 외부 파트너는 언급되지 않았으므로 생성하지 않는다.",
    "예산 정보는 언급되지 않았으므로 생성하지 않는다.",
    "보안 사고, 운영 장애, 법무 승인 요구사항은 언급되지 않았으므로 생성하지 않는다.",
    "담당자가 없는 항목은 owner를 null로 둔다.",
    "정확한 마감이 없는 항목은 due를 null 또는 원문 수준의 조건으로만 기록한다.",
    "수요일은 공개 릴리스 결정이 아니라 내부 stretch goal로만 기록한다."
  ]
}
